#include<bits/stdc++.h>
using namespace std;
long long u[100010],d[100010],a[100010];
const long long mod=998244353;
int main()
{
    long long n;
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    long long ans=0;
    for(long long i=1;i<=n;i++)
    {
        long long sum=1,sum1=0;
        for(long long j=i;j<=n;j++)
        {
            u[j]=a[j];
            d[j]=j-i+1;
            if(u[j]<d[j])
            {
                break;
            }
            sum=sum*((u[j]-d[j]+1)%mod)%mod;
            sum1=(sum1+1ll*(u[j]+d[j])%mod*499122177%mod)%mod;
            ans+=sum*sum1%mod;
            ans%=mod;
        }
    }
    printf("%lld",ans);
    return 0;
}
